export function getArkPassiveNodeMeta(id) {
  return ARK_PASSIVE_NODE_META[Number(id)] || null;
}

export function getSpecFromArkPassiveNodeId(id) {
  return ENLIGHTENMENT_SPEC_BY_NODE_ID[Number(id)] || "";
}

export function getSpecFromArkPassiveNodes(nodes) {
  for (const node of Array.isArray(nodes) ? nodes : []) {
    const spec = getSpecFromArkPassiveNodeId(node?.id);
    if (spec) return spec;
  }
  return "";
}
